							      begin try
								        set @ChangeDescription = ''

							            SELECT 
                                               @NewID_Connection_String = I.ID_Connection_String,
											   @NewPassword             = I.[Password]          ,  
											   @NewLogin                = I.[Login]             ,  
											   @NewDate_Created         = I.Date_Created        ,
											   @NewDescription          = I.[Description]          	
							            FROM inserted I									 
							            where @ID_entity_D = I.ID_Connection_String;

                                        SELECT 
