						   ,login_name   
						   ,ModifiedDate 
						   ,Name_action  
						   from @t_U_D 
                           open cr       
						   
						   fetch next from cr into 
						   @ID_entity_D,@login_name_2_D,@ModifiedDate_D,@Name_action_D 
						   while @@FETCH_STATUS  = 0
						       begin
							      begin try
								        set @ChangeDescription = ''

							            SELECT 
                                              @NewID_Post         = I.ID_Post        , 
											  @NewName_Post       = I.Name_Post      , 
											  @NewID_Department   = I.ID_Department  , 
