										   where @ID_entity_D_2 = D.ID_Species_Item;

                                           SET @ChangeDescription = 'Deleted: '
							               + 'ID_Species_Item'       +' = "'+  ISNULL(CAST(@OldID_Species_Item_2  AS NVARCHAR(50)),'')+ '", '
							               + 'SpeciesItemName'       +' = "'+  ISNULL(@OldSpeciesItemName_2,'')+ '", '
