						       begin
							      begin try
								        set @ChangeDescription = ''

							            SELECT 
										     @NewID_The_Subgroup           = I.ID_The_Subgroup          ,
											 @NewID_Head_The_Subgroup      = I.ID_Head_The_Subgroup     ,
											 @NewID_Vice_Head_The_Subgroup = I.ID_Vice_Head_The_Subgroup,
