							            where @ID_entity_D = I.ID_The_Subgroup;								        

                                        SELECT 
										     @OldID_The_Subgroup           = D.ID_The_Subgroup          ,
											 @OldID_Head_The_Subgroup      = D.ID_Head_The_Subgroup     ,
