						    while @@FETCH_STATUS  = 0
						         begin
							         begin try
									        set @ChangeDescription = ''

                                            SELECT 
										              @OldID_The_Subgroup_2           = D.ID_The_Subgroup          ,
											          @OldID_Head_The_Subgroup_2      = D.ID_Head_The_Subgroup     ,
											          @OldID_Vice_Head_The_Subgroup_2 = D.ID_Vice_Head_The_Subgroup,
