declare @i int = 0, @s int = 0 , @n varchar(40), @mess varchar(8000), @err varchar(1000)

declare
@ID_Branch       bigint  
,@Id_Country     bigint       
,@City         	 nvarchar(100)
,@Address    	 nvarchar(300)
,@Name_Branch  	 nvarchar(300)
,@Mail           nvarchar(300)
,@Phone          nvarchar(15)
,@Postal_Code    int
,@INN            int	
,@Description    nvarchar(max)
,@flag           int
declare mycur cursor local fast_forward for

select 
 b.ID_Branch    
,b.Id_Country   
,b.City         
,b.[Address]    
,b.Name_Branch  
,t.Mail         
,t.Phone        
,t.Postal_Code  
,b.INN          
,t.[Description]
,0 as flag 
from #t t inner join Branch b on b.ID_Branch = t.ID_Branch


open mycur
fetch next from mycur into
@ID_Branch   
,@Id_Country 
,@City       
,@Address    
,@Name_Branch
,@Mail       
,@Phone      
,@Postal_Code
,@INN        
,@Description
,@flag 
while @@FETCH_STATUS  = 0
               -- (0,-1,-2,-9) столбец fetch_status функции динамического управления sys.dm_exec_cursors
			   -- 0 Инструкция FETCH была выполнена успешно.
			   ---1	Выполнение инструкции FETCH завершилось неудачно или строка оказалась вне пределов результирующего набора.
			   ---2	Выбранная строка отсутствует.
			   --–9	Курсор не выполняет операцию выборки.
    begin
	  begin try
	      begin tran
			   update   b
			   set 
			    Mail = @Mail
			   ,Phone = @Phone
			   ,Postal_Code = @Postal_Code
			   ,[Description] = @Description
			   from  Branch as b
			   where  Id_Branch = @Id_Branch

			  set @i =  @i + 1
			  if exists (select * 
			             from Branch 
			             where 1 =1
			             and  Mail = @Mail
						 and  Phone = @Phone
						 and  Postal_Code = @Postal_Code
						 and  [Description] = @Description
						 )  
				   begin 
				        update m set flag = 1 from #t  as m where ID_Branch = @ID_Branch and flag = 0
				   end
          --rollback
		  commit
			  select @s = count(0) from #t where flag = 0
			  set @n = (select  
			            case  t.flag  when 1 then ' 1  Значения внесены' when 0  then ' 0  Значения не изменились' end  
			            from #t t  where ID_Branch = @ID_Branch)
			  set @mess = @n + ' - > ' +  ' Объект ' + cast(@ID_Branch as varchar)  +  ' --> ' + ' - ' + Cast(@i as varchar) + ' / ' + Cast(@s as varchar)
			  RAISERROR(@mess,0,0) WITH NOWAIT

       end try

	   begin catch
                if @@trancount > 0
                begin
                   rollback;
                end;
                
                set @err = formatmessage(N'ID=%I64d, error - %s', @ID_Branch, error_message());
                print @err;
       end catch;
            	   

	fetch next from mycur into 
	@ID_Branch   
	,@Id_Country 
	,@City       
	,@Address    
	,@Name_Branch
	,@Mail       
	,@Phone      
	,@Postal_Code
	,@INN        
	,@Description
	,@flag
	end
close mycur
deallocate mycur

declare @Branch int;
set @Branch = (select count(ID_Branch) as ID_Branch from Branch)
print 'Заполнена таблица dbo.Branch. Общее количество заполненных строк --> ' +  cast(@Branch as nvarchar(500))


