        AND (bg.Статус_заказа IS NULL OR t.id_status_order = bg.Статус_заказа)
		and bg.ID_Currency = ID_Currency
) ids
ORDER BY 
    bg.Дата,
    bg.Группа_статусов,
    bg.Статус_заказа;

