drop table if exists #t_5_1
	 
    select
	row_number() over (order by t.Группа_статусов) as 'Нумерация'
	,t.* 
	into #t_5_1
	from(
	select *
	from #t_4  t
	where  Количество_экземпляров = 1 and Группа_статусов is not null
	Union all
	select * 
	from #t_4  
	where Количество_экземпляров > 1 and Группа_статусов is not null
	Union all
	select *
	from #t_4_1  t
	where  Количество_экземпляров = 1 and Группа_статусов is not null
	Union all
	select * 
	from #t_4_1  
	where Количество_экземпляров > 1 and Группа_статусов is not null
	) as t order by t.Дата,t.Количество_экземпляров

