,t.Количество_экземпляров	
,t.Список_ID	
,t.Цена_без_НДС_экземпляра	
,t.Общая_стоимость_с_НДС	
,t.Цена_экземпляра_с_НДС_после_начисления_коммисии_за_сервис	
,t.Цена_экземпляра_без_НДС_после_начисления_коммисии_за_сервис
,0 flag
